SELECT terrain_name, elevation
FROM terrains
WHERE elevation > 1000;

SELECT land_use_id, land_use_name, description, building_density
FROM land_uses
WHERE population_density > 400;

SELECT COUNT(*) AS total_users
FROM (
    SELECT created_by AS user_name FROM reports
    UNION
    SELECT last_modified_by FROM reports
) AS unique_users;

SELECT phone_number
FROM users
WHERE role = 'admin';

SELECT ad_sys_name
FROM administrative_systems
WHERE ad_sys_name = 'Local';

SELECT terrain_name, elevation
FROM terrains
ORDER BY elevation DESC;

SELECT pavement_type_name, condition
FROM pavement_types
WHERE age > 5;

SELECT terrain_name
FROM terrains
WHERE elevation = (SELECT MAX(elevation) FROM terrains) AND slope_percentage >= 5;

SELECT terrains.terrain_name, risk_factors.risk_factor_name
FROM terrains, risk_factors
WHERE terrains.terrain_id = 1 AND risk_factors.risk_factor_id = 1;

SELECT DISTINCT ad_sys_name 
FROM administrative_systems 
WHERE ad_sys_id IN (SELECT ad_sys_id FROM reports);

SELECT risk_factor_name, description
FROM risk_factors
WHERE risk_factor_name = 'High Traffic Density';

SELECT AVG(elevation) AS average_elevation
FROM terrains
WHERE elevation > (SELECT AVG(elevation) FROM terrains);

SELECT u.user_name, u.role, g.gov_cont_name
FROM users u
JOIN government_controls g ON u.user_id = g.gov_cont_id;

SELECT 
    (SELECT user_name FROM users WHERE last_login = (SELECT MAX(last_login) FROM users)) as most_recent_user,
    (SELECT access_type FROM access_logs GROUP BY access_type ORDER BY COUNT(*) DESC LIMIT 1) as most_common_access_type;
